div.script:
function previewImage(input) {
    if (input.files && input.files[0]) {
        var reader = new FileReader();

        // Show loading animation
        document.getElementById('upload_prompt').classList.add('tw-hidden');
        document.getElementById('image_preview_container').classList.add('tw-hidden');
        document.getElementById('loading_state').classList.remove('tw-hidden');

        reader.onload = function(e) {
            // Add a slight delay for the animation effect
            setTimeout(function() {
                document.getElementById('loading_state').classList.add('tw-hidden');
                document.getElementById('image_preview_container').classList.remove('tw-hidden');
                document.getElementById('image_preview').src = e.target.result;
            }, 1200); // 1.2 second loading simulation
        }

        reader.readAsDataURL(input.files[0]);
    }
}
